+    fn resolved_writes_for_commit_honors_strict_policy() {
+        let mut store = MvccStore::new();
+        store.set_conflict_policy(ConflictPolicy::Strict);
+        let block = BlockNumber(7);
+        seed_block(&mut store, block, &[0]);
